import React, { useState, useEffect } from 'react';
import axios from 'axios';

function AccountManagement() {
  const [accounts, setAccounts] = useState([]);
  const [showCreateForm, setShowCreateForm] = useState(false);
  const [formData, setFormData] = useState({
    customerId: '',
    accountType: 'CURRENT',
    currency: 'EUR',
    balance: 0,
    iban: '',
  });

  useEffect(() => {
    fetchAccounts();
  }, []);

  const fetchAccounts = async () => {
    try {
      // Mock data - replace with API call
      const mockAccounts = [
        {
          accountId: 'ACC001',
          customerId: 'CUST001',
          accountType: 'CURRENT',
          currency: 'EUR',
          balance: 5250.75,
          status: 'ACTIVE',
          iban: 'SK9212345678901234567890',
          createdAt: '2024-01-15T10:30:00',
        },
        {
          accountId: 'ACC002',
          customerId: 'CUST001',
          accountType: 'SAVINGS',
          currency: 'EUR',
          balance: 12500.00,
          status: 'ACTIVE',
          iban: 'SK9212345678901234567891',
          createdAt: '2024-02-20T14:45:00',
        },
      ];
      setAccounts(mockAccounts);
    } catch (error) {
      console.error('Error fetching accounts:', error);
    }
  };

  const handleCreate = async (e) => {
    e.preventDefault();
    try {
      // TODO: Call API Gateway POST /api/accounts
      console.log('Creating account:', formData);
      setShowCreateForm(false);
      setFormData({
        customerId: '',
        accountType: 'CURRENT',
        currency: 'EUR',
        balance: 0,
        iban: '',
      });
      // fetchAccounts();
    } catch (error) {
      console.error('Error creating account:', error);
    }
  };

  return (
    <div>
      <div className="card">
        <h3>💳 Account Management</h3>
        <button className="btn-primary" onClick={() => setShowCreateForm(!showCreateForm)}>
          {showCreateForm ? '✖ Cancel' : '➕ Create New Account'}
        </button>

        {showCreateForm && (
          <form onSubmit={handleCreate} style={{ marginTop: '20px' }}>
            <div className="form-group">
              <label>Customer ID</label>
              <input
                type="text"
                value={formData.customerId}
                onChange={(e) =>
                  setFormData({ ...formData, customerId: e.target.value })
                }
                required
              />
            </div>
            <div className="form-group">
              <label>Account Type</label>
              <select
                value={formData.accountType}
                onChange={(e) =>
                  setFormData({ ...formData, accountType: e.target.value })
                }
              >
                <option>CURRENT</option>
                <option>SAVINGS</option>
                <option>CORPORATE</option>
              </select>
            </div>
            <div className="form-group">
              <label>Currency</label>
              <input
                type="text"
                value={formData.currency}
                onChange={(e) =>
                  setFormData({ ...formData, currency: e.target.value })
                }
              />
            </div>
            <div className="form-group">
              <label>Initial Balance</label>
              <input
                type="number"
                value={formData.balance}
                onChange={(e) =>
                  setFormData({ ...formData, balance: parseFloat(e.target.value) })
                }
              />
            </div>
            <button type="submit" className="btn-primary">
              Create Account
            </button>
          </form>
        )}
      </div>

      <div className="card" style={{ marginTop: '20px' }}>
        <h3>📋 All Accounts</h3>
        <table className="table">
          <thead>
            <tr>
              <th>Account ID</th>
              <th>Type</th>
              <th>IBAN</th>
              <th>Balance</th>
              <th>Status</th>
              <th>Created</th>
            </tr>
          </thead>
          <tbody>
            {accounts.map((acc) => (
              <tr key={acc.accountId}>
                <td>{acc.accountId}</td>
                <td>{acc.accountType}</td>
                <td>{acc.iban}</td>
                <td>€{acc.balance.toFixed(2)}</td>
                <td>
                  <span style={{ color: acc.status === 'ACTIVE' ? 'green' : 'red' }}>
                    {acc.status}
                  </span>
                </td>
                <td>{new Date(acc.createdAt).toLocaleDateString()}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
}

export default AccountManagement;
